'use client';
import { useState, useEffect } from 'react';

const USERS: Record<string, string> = {
  bruno:   process.env.NEXT_PUBLIC_PASS_BRUNO   || 'anb2024',
  nelson:  process.env.NEXT_PUBLIC_PASS_NELSON  || 'anb2024',
  alex:    process.env.NEXT_PUBLIC_PASS_ALEX    || 'anb2024',
};

export function useAuth() {
  const [authed, setAuthed] = useState<boolean | null>(null);

  useEffect(() => {
    const session = sessionStorage.getItem('anb_session');
    setAuthed(session === 'ok');
  }, []);

  function login(user: string, pass: string): boolean {
    if (USERS[user.toLowerCase()] && USERS[user.toLowerCase()] === pass) {
      sessionStorage.setItem('anb_session', 'ok');
      sessionStorage.setItem('anb_user', user);
      setAuthed(true);
      return true;
    }
    return false;
  }

  function logout() {
    sessionStorage.removeItem('anb_session');
    sessionStorage.removeItem('anb_user');
    setAuthed(false);
  }

  function getUser() {
    return typeof window !== 'undefined' ? sessionStorage.getItem('anb_user') || '' : '';
  }

  return { authed, login, logout, getUser };
}

export function LoginPage({ onLogin }: { onLogin: (u: string, p: string) => boolean }) {
  const [user, setUser]   = useState('');
  const [pass, setPass]   = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    setError('');
    setTimeout(() => {
      const ok = onLogin(user, pass);
      if (!ok) setError('Usuário ou senha incorretos');
      setLoading(false);
    }, 400);
  }

  return (
    <div style={{
      minHeight: '100vh', display: 'flex', alignItems: 'stretch',
      fontFamily: "'Inter', system-ui, sans-serif",
    }}>
      {/* Painel esquerdo — azul ANB */}
      <div style={{
        width: 420, background: '#0a1628',
        display: 'flex', flexDirection: 'column',
        alignItems: 'center', justifyContent: 'center',
        padding: '48px 40px', flexShrink: 0,
      }}>
        <img
          src={'data:image/jpeg;base64,'}
          alt="ANB Parts"
          style={{ width: 110, height: 110, borderRadius: 20, objectFit: 'cover', marginBottom: 28 }}
        />
        <div style={{ fontSize: 26, fontWeight: 700, color: '#fff', letterSpacing: '-0.5px', marginBottom: 6 }}>ANB Parts</div>
        <div style={{ fontSize: 13, color: 'rgba(255,255,255,.4)', fontFamily: "'JetBrains Mono', monospace", marginBottom: 48 }}>Sistema de Gestão Interna</div>

        <div style={{ width: '100%' }}>
          {[
            { label: '🏍', text: 'Gestão de motos e peças' },
            { label: '📦', text: 'Controle de estoque' },
            { label: '🔗', text: 'Integração com Bling ERP' },
            { label: '💰', text: 'Faturamento e DRE' },
          ].map((item, i) => (
            <div key={i} style={{
              display: 'flex', alignItems: 'center', gap: 12,
              padding: '10px 0', borderBottom: '1px solid rgba(255,255,255,.06)',
              fontSize: 13, color: 'rgba(255,255,255,.55)',
            }}>
              <span style={{ fontSize: 16, width: 24, textAlign: 'center' }}>{item.label}</span>
              {item.text}
            </div>
          ))}
        </div>
      </div>

      {/* Painel direito — login */}
      <div style={{
        flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center',
        background: '#f8fafc', padding: 40,
      }}>
        <div style={{ width: '100%', maxWidth: 360 }}>
          <div style={{ marginBottom: 32 }}>
            <div style={{ fontSize: 24, fontWeight: 700, color: '#1e293b', letterSpacing: '-0.4px', marginBottom: 6 }}>Bem-vindo de volta</div>
            <div style={{ fontSize: 13.5, color: '#94a3b8' }}>Entre com suas credenciais para acessar o sistema.</div>
          </div>

          <form onSubmit={handleSubmit}>
            <div style={{ marginBottom: 16 }}>
              <label style={{ fontSize: 12, fontWeight: 500, color: '#475569', display: 'block', marginBottom: 6 }}>Usuário</label>
              <input
                value={user} onChange={e => setUser(e.target.value)}
                placeholder="bruno, nelson ou alex"
                autoFocus
                style={{
                  width: '100%', background: '#fff',
                  border: '1px solid #e2e8f0', borderRadius: 8,
                  padding: '10px 14px', fontSize: 14,
                  outline: 'none', color: '#1e293b',
                  transition: '150ms',
                }}
                onFocus={e => e.target.style.borderColor='#3b82f6'}
                onBlur={e => e.target.style.borderColor='#e2e8f0'}
              />
            </div>

            <div style={{ marginBottom: 24 }}>
              <label style={{ fontSize: 12, fontWeight: 500, color: '#475569', display: 'block', marginBottom: 6 }}>Senha</label>
              <input
                type="password" value={pass} onChange={e => setPass(e.target.value)}
                placeholder="••••••••"
                style={{
                  width: '100%', background: '#fff',
                  border: '1px solid #e2e8f0', borderRadius: 8,
                  padding: '10px 14px', fontSize: 14,
                  outline: 'none', color: '#1e293b',
                  transition: '150ms',
                }}
                onFocus={e => e.target.style.borderColor='#3b82f6'}
                onBlur={e => e.target.style.borderColor='#e2e8f0'}
              />
            </div>

            {error && (
              <div style={{
                background: '#fee2e2', border: '1px solid #fca5a5',
                borderRadius: 8, padding: '10px 14px',
                fontSize: 13, color: '#dc2626', marginBottom: 18,
              }}>
                ✗ {error}
              </div>
            )}

            <button
              type="submit"
              disabled={loading || !user || !pass}
              style={{
                width: '100%', background: '#1e56a0', color: '#fff',
                border: 'none', borderRadius: 8, padding: '11px 20px',
                fontSize: 14, fontWeight: 600, cursor: 'pointer',
                opacity: loading || !user || !pass ? 0.6 : 1,
                transition: '150ms', fontFamily: "'Inter', sans-serif",
              }}
            >
              {loading ? 'Entrando...' : 'Entrar'}
            </button>
          </form>

          <div style={{ marginTop: 32, fontSize: 11, color: '#94a3b8', textAlign: 'center', fontFamily: "'JetBrains Mono', monospace" }}>
            ANB Parts © {new Date().getFullYear()}
          </div>
        </div>
      </div>
    </div>
  );
}
